/**
 * Notification model — core types for the notification system.
 *
 * Architecture: All notifications flow through the EventBus. Services emit
 * domain events (e.g., order:created), and the NotificationService subscribes
 * to those events and dispatches notifications through registered adapters.
 *
 * Constraints:
 * - All delivery adapters must implement the NotificationAdapter interface.
 * - All notifications must go through EventBus.emit() — no direct service calls.
 * - Each NotificationChannel has exactly one adapter registered for it.
 */

/**
 * Supported notification delivery channels.
 * New channels (e.g., 'sms', 'push', 'slack') can be added here
 * and a corresponding adapter registered with the NotificationService.
 */
export type NotificationChannel = 'email' | 'in-app';

/**
 * Notification priority levels.
 */
export type NotificationPriority = 'low' | 'normal' | 'high' | 'urgent';

/**
 * The type of event that triggered the notification.
 */
export type NotificationType =
  | 'order-confirmation'
  | 'order-status-update'
  | 'welcome'
  | 'account-updated';

/**
 * Payload passed to notification adapters for delivery.
 */
export interface NotificationPayload {
  /** Unique notification ID. */
  id: string;
  /** What triggered this notification. */
  type: NotificationType;
  /** Delivery channel for this notification. */
  channel: NotificationChannel;
  /** Recipient identifier (email address, user ID, etc. depending on channel). */
  recipient: string;
  /** Notification subject line. */
  subject: string;
  /** Notification body content. */
  body: string;
  /** Priority level. */
  priority: NotificationPriority;
  /** When the notification was created. */
  createdAt: Date;
  /** Arbitrary metadata from the originating event. */
  metadata?: Record<string, unknown>;
}

/**
 * Result returned by an adapter after attempting delivery.
 */
export interface NotificationResult {
  /** Whether delivery succeeded. */
  success: boolean;
  /** The notification that was sent. */
  notification: NotificationPayload;
  /** When delivery was attempted. */
  deliveredAt: Date;
  /** Error message if delivery failed. */
  error?: string;
}

/**
 * Interface that all notification delivery adapters must implement.
 *
 * To add a new notification channel:
 * 1. Add the channel name to the NotificationChannel type above.
 * 2. Create an adapter class implementing this interface.
 * 3. Register it with NotificationService.registerAdapter().
 */
export interface NotificationAdapter {
  /** Which channel this adapter handles. */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this channel.
   * Must return a NotificationResult indicating success or failure.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that stores sent emails in memory.
 * A real implementation would integrate with an email provider
 * (e.g., SendGrid, SES, SMTP).
 *
 * Implements the NotificationAdapter interface so it can be registered
 * with the NotificationService.
 */

import type {
  NotificationAdapter,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;

  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    const email: SentEmail = {
      to: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: new Date(),
    };

    this.sentEmails.push(email);

    return {
      success: true,
      notification: payload,
      deliveredAt: email.sentAt,
    };
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — dispatches notifications through registered adapters
 * in response to EventBus events.
 *
 * Architecture: Event-driven only. All notifications originate from EventBus
 * events. The service maps domain events to NotificationPayloads and routes
 * them through the appropriate NotificationAdapter based on channel.
 *
 * Constraints:
 * - All adapters must implement the NotificationAdapter interface.
 * - All notifications must flow through EventBus.emit() — no direct calls.
 * - One adapter per channel. Registering a second adapter for the same
 *   channel replaces the first.
 *
 * To extend:
 * 1. Subscribe to new event types in registerEventHandlers().
 * 2. Add adapter for new channels via registerAdapter().
 *
 * Depends on:
 * - EventBus (event system) for receiving all domain events
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
} from '../events/event-types.js';
import type {
  NotificationAdapter,
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
  NotificationType,
  NotificationPriority,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private results: NotificationResult[] = [];

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a delivery adapter for a notification channel.
   * One adapter per channel — registering a second replaces the first.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registering adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to domain events on the EventBus.
   * All notification triggers are registered here.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) =>
      this.handleOrderCreated(event),
    );

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) =>
      this.handleOrderStatusChanged(event),
    );

    this.eventBus.on<UserCreatedEvent>('user:created', (event) =>
      this.handleUserCreated(event),
    );
  }

  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.send({
      type: 'order-confirmation',
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      priority: 'normal',
      metadata: { orderId: event.order.id, userId: event.user.id },
    });
  }

  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    await this.send({
      type: 'order-status-update',
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      priority: 'normal',
      metadata: {
        orderId: event.order.id,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    });
  }

  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    await this.send({
      type: 'welcome',
      channel: 'email',
      recipient: event.user.email,
      subject: `Welcome to TaskFlow Pro, ${event.user.name}!`,
      body: `Your account has been created. You can start using the platform right away.`,
      priority: 'normal',
      metadata: { userId: event.user.id },
    });
  }

  /**
   * Send a notification through the appropriate adapter.
   * Creates a full NotificationPayload and delegates to the registered adapter.
   */
  async send(params: {
    type: NotificationType;
    channel: NotificationChannel;
    recipient: string;
    subject: string;
    body: string;
    priority?: NotificationPriority;
    metadata?: Record<string, unknown>;
  }): Promise<NotificationResult> {
    const payload: NotificationPayload = {
      id: generateNotificationId(),
      type: params.type,
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      priority: params.priority ?? 'normal',
      createdAt: new Date(),
      metadata: params.metadata,
    };

    const adapter = this.adapters.get(params.channel);
    if (!adapter) {
      this.logger.warn(`No adapter registered for channel: ${params.channel}`);
      const result: NotificationResult = {
        success: false,
        notification: payload,
        deliveredAt: new Date(),
        error: `No adapter registered for channel: ${params.channel}`,
      };
      this.results.push(result);
      return result;
    }

    this.logger.info(`Sending ${params.type} notification via ${params.channel} to ${params.recipient}`);

    const result = await adapter.send(payload);
    this.results.push(result);
    return result;
  }

  /**
   * Get all notification results (successes and failures).
   */
  getResults(): NotificationResult[] {
    return [...this.results];
  }

  /**
   * Get results for a specific recipient.
   */
  getResultsForRecipient(recipient: string): NotificationResult[] {
    return this.results.filter((r) => r.notification.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.results.length;
  }

  /**
   * Clear all results (useful for testing).
   */
  clearResults(): void {
    this.results = [];
  }
}

